#include <stdio.h>
#include <limits.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int K; long long X; scanf("%d %lld", &K, &X);
        long long answer = 0;
        for (int i = 0; i < K; ++i) {
            int N; scanf("%d", &N);
            long long mn = LLONG_MAX, mx = LLONG_MIN;
            for (int j = 0; j < N; ++j) {
                long long v; scanf("%lld", &v);
                if (v < mn) mn = v;
                if (v > mx) mx = v;
            }
            if (mn / X == mx / X) ++answer;
        }
        printf("%lld\n", answer);
    }
    return 0;
}

